SELECT A.BRD_ID brd_id , A.BRD_NM brd_nm , A.BRD_NM2 brd_nm2 , A.BRD_LEVEL brd_level , A.BRD_STEP brd_step , A.BRD_POSTTERM brd_postterm , A.BRD_UPPER brd_upper , A.BRD_GB brd_gb , A.BRD_URL brd_url , A.BRD_EXPLAIN brd_explain , A.BRD_ACCESS brd_access , A.ATTACH_SIZE attach_size , ( SELECT IFNULL(COUNT(BRD_ID) , 0) FROM TBL_RS_BRD WHERE BRD_UPPER = A.BRD_ID AND Brd_Company = #v_P_CompanyID# AND Brd_GB = '1' AND TENANT_ID = #tenantID# ) sub_clscnt , ( SELECT IFNULL(COUNT(BRD_ID) , 0) FROM TBL_RS_BRD WHERE BRD_UPPER = A.BRD_ID AND Brd_Company = #v_P_CompanyID# AND Brd_GB = '2' AND TENANT_ID = #tenantID#
AND APPROVEFLAG <> '2'
) sub_rescnt , '0' Access_Lvl , A.APPROVEFLAG FROM TBL_RS_BRD A WHERE Brd_Upper = IFNULL(#v_P_ParentID#,0) AND Brd_Company = #v_P_CompanyID# AND TENANT_ID = #tenantID# ORDER BY Brd_GB, Brd_Step

